import React, {createContext, type FC, type PropsWithChildren, useContext, useEffect, useState} from 'react';
import type {IThemeContextProps, IThemeContextValues} from '@lmb-it/kitsconcerto-types';
import {useColorScheme} from 'react-native';

const ThemeContext = createContext<IThemeContextValues>({} as IThemeContextValues);

const ThemeContextProvider: FC<PropsWithChildren<IThemeContextProps>> = ({children,theme }) => {
    const systemScheme = useColorScheme();
    const [selectedTheme, setTheme] = useState<'light' | 'dark'>(systemScheme ?? 'light');
    const [colorMode, setColorMode] = useState<any>();


    useEffect(() => {
        theme && setTheme(theme)
    }, [theme]);
    const switchTheme = (themeFile?: string) => {
        const newTheme = selectedTheme === 'dark' ? 'light' : 'dark';
        setTheme(newTheme);
        if (setColorMode) setColorMode(newTheme);
    };

    return (
        <ThemeContext.Provider value={{switchTheme, theme:selectedTheme}}>
            {children}
        </ThemeContext.Provider>
    );
};

export default ThemeContextProvider;
export const useTheme = () => useContext(ThemeContext);

export {KitsThemeProvider, useKitsTheme, useNativeColorMap} from './KitsThemeProvider.native';
export {extendTheme, deepMerge} from './utils';
